#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100
#define MAXM 10000
int n, m;
int adj[MAXN][MAXN];
int dist[MAXN][MAXN];
void bfs(int start) {
    int queue[MAXN];
    int front, rear;
    front = rear = 0;
    queue[rear++] = start;
    dist[start][start] = 0;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (adj[u][v] && dist[start][v] == -1) {
                dist[start][v] = dist[start][u] + 1;
                queue[rear++] = v;
            }
        }
    }
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d", &n, &m);
        memset(adj, 0, sizeof(adj));
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            adj[u][v] = adj[v][u] = 1;
        }
        for (int i = 0; i < n; i++) {
            memset(dist, -1, sizeof(dist));
            bfs(i);
        }
        // Construct the directed graph G'
        int g_prime[MAXN][MAXN];
        memset(g_prime, 0, sizeof(g_prime));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][j] != -1) {
                    g_prime[i][j] = 1;
                }
            }
        }
        // Check if there exists a pair of nodes in G' that are not connected by a path
        int found = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (!g_prime[i][j]) {
                    found = 1;
                    break;
                }
            }
            if (found) break;
        }
        if (found) {
            printf("YES\n");
            for (int i = 0; i < n; i++) {
                printf("1 ");
            }
            printf("\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

